// ======================================================
// AI Analytics Engine - Part 1
// Run Once for All Items
// ======================================================

// Read all incoming rows
const items = $input.all();
const rawRows = items.map(item => item.json);

// ------------------------------------------------------
// Helper Functions
// ------------------------------------------------------

const isEmpty = (value) => {
    return value === null ||
           value === undefined ||
           value === "" ||
           value === "NULL" ||
           value === "null" ||
           value === "NaN";
};

const toNumber = (value) => {
    if (typeof value === "number") return value;

    const num = Number(
        String(value)
            .replace(/,/g, "")
            .replace(/%/g, "")
            .trim()
    );

    return isNaN(num) ? null : num;
};

// ------------------------------------------------------
// Clean Dataset
// ------------------------------------------------------

const cleanedRows = rawRows.map(row => {

    const clean = {};

    Object.entries(row).forEach(([key, value]) => {

        if (typeof value === "string") {
            value = value.trim();
        }

        clean[key] = value;

    });

    return clean;

});

// ------------------------------------------------------
// Dataset Metadata
// ------------------------------------------------------

const metadata = {

    total_rows: cleanedRows.length,

    total_columns:
        cleanedRows.length > 0
            ? Object.keys(cleanedRows[0]).length
            : 0,

    generated_at: new Date().toISOString()

};

// ------------------------------------------------------
// Detect Schema
// ------------------------------------------------------

const schema = [];

if (cleanedRows.length > 0) {

    const firstRow = cleanedRows[0];

    Object.keys(firstRow).forEach(column => {

        let numeric = 0;
        let missing = 0;
        let unique = new Set();

        cleanedRows.forEach(row => {

            const value = row[column];

            if (isEmpty(value)) {

                missing++;

            } else {

                unique.add(value);

                if (toNumber(value) !== null) {
                    numeric++;
                }

            }

        });

        schema.push({

            column,

            detected_type:
                numeric > cleanedRows.length * 0.7
                    ? "numeric"
                    : "categorical",

            missing,

            unique_values: unique.size

        });

    });

}

// ------------------------------------------------------
// Dataset Profile
// ------------------------------------------------------

const profile = {

    numeric_columns:
        schema.filter(c => c.detected_type === "numeric")
              .map(c => c.column),

    categorical_columns:
        schema.filter(c => c.detected_type === "categorical")
              .map(c => c.column)

};
// ======================================================
// KPI ENGINE
// ======================================================

const kpis = {
    total_records: cleanedRows.length,
    total_numeric_columns: profile.numeric_columns.length,
    total_categorical_columns: profile.categorical_columns.length,
    total_missing_values: 0,
    completeness: 0
};

schema.forEach(col => {
    kpis.total_missing_values += col.missing;
});

const totalCells = metadata.total_rows * metadata.total_columns;

kpis.completeness =
    totalCells > 0
        ? (((totalCells - kpis.total_missing_values) / totalCells) * 100).toFixed(2)
        : 0;

// ======================================================
// STATISTICAL ANALYSIS
// ======================================================

const statistics = {};

profile.numeric_columns.forEach(column => {

    const values = cleanedRows
        .map(r => toNumber(r[column]))
        .filter(v => v !== null);

    if (!values.length) return;

    values.sort((a, b) => a - b);

    const sum = values.reduce((a, b) => a + b, 0);

    const mean = sum / values.length;

    const median =
        values.length % 2
            ? values[Math.floor(values.length / 2)]
            : (
                values[values.length / 2 - 1] +
                values[values.length / 2]
              ) / 2;

    const variance =
        values.reduce((a, b) => a + Math.pow(b - mean, 2), 0) /
        values.length;

    statistics[column] = {

        count: values.length,

        min: Math.min(...values),

        max: Math.max(...values),

        mean: Number(mean.toFixed(2)),

        median: Number(median.toFixed(2)),

        sum: Number(sum.toFixed(2)),

        standard_deviation: Number(Math.sqrt(variance).toFixed(2))

    };

});

// ======================================================
// CATEGORY ANALYSIS
// ======================================================

const categoryAnalysis = {};

profile.categorical_columns.forEach(column => {

    const freq = {};

    cleanedRows.forEach(row => {

        const value = row[column];

        if (isEmpty(value)) return;

        freq[value] = (freq[value] || 0) + 1;

    });

    const sorted = Object.entries(freq)
        .sort((a, b) => b[1] - a[1]);

    categoryAnalysis[column] = {

        unique_categories: sorted.length,

        top_categories: sorted.slice(0, 10)

    };

});

// ======================================================
// BASIC DATASET INSIGHTS
// ======================================================

const insights = [];

insights.push(
    `Dataset contains ${metadata.total_rows} records and ${metadata.total_columns} columns.`
);

insights.push(
    `${profile.numeric_columns.length} numeric columns detected.`
);

insights.push(
    `${profile.categorical_columns.length} categorical columns detected.`
);

if (kpis.total_missing_values > 0) {

    insights.push(
        `${kpis.total_missing_values} missing values found in the dataset.`
    );

} else {

    insights.push(
        "No missing values detected."
    );

}
// ======================================================
// RELATIONSHIP DETECTION
// ======================================================

const relationships = [];

profile.numeric_columns.forEach(column => {

    const stats = statistics[column];

    if (!stats) return;

    relationships.push({
        column,
        average: stats.mean,
        minimum: stats.min,
        maximum: stats.max,
        spread: Number((stats.max - stats.min).toFixed(2))
    });

});

// ======================================================
// OUTLIER DETECTION (IQR)
// ======================================================

const outliers = {};

profile.numeric_columns.forEach(column => {

    const values = cleanedRows
        .map(r => toNumber(r[column]))
        .filter(v => v !== null)
        .sort((a,b)=>a-b);

    if(values.length < 4) return;

    const q1 = values[Math.floor(values.length * 0.25)];
    const q3 = values[Math.floor(values.length * 0.75)];

    const iqr = q3 - q1;

    const lower = q1 - 1.5 * iqr;
    const upper = q3 + 1.5 * iqr;

    outliers[column] = values.filter(v => v < lower || v > upper);

});

// ======================================================
// DATA QUALITY ANALYSIS
// ======================================================

const quality_analysis = {

    total_rows: metadata.total_rows,

    total_columns: metadata.total_columns,

    missing_values: kpis.total_missing_values,

    completeness: kpis.completeness,

    duplicate_rows:
        cleanedRows.length -
        new Set(cleanedRows.map(r => JSON.stringify(r))).size

};

quality_analysis.quality_score = Number(

    Math.max(

        0,

        (
            quality_analysis.completeness
            -
            quality_analysis.duplicate_rows
        )

    ).toFixed(2)

);

// ======================================================
// CHART RECOMMENDATION ENGINE
// ======================================================

const charts = [];

profile.numeric_columns.forEach(column=>{

    charts.push({

        title: column,

        chart_type: "bar",

        labels: cleanedRows
                    .slice(0,10)
                    .map((_,i)=>`Row ${i+1}`),

        values: cleanedRows
                    .slice(0,10)
                    .map(r=>toNumber(r[column]) || 0)

    });

});

profile.categorical_columns.forEach(column=>{

    const freq={};

    cleanedRows.forEach(r=>{

        const v=r[column];

        if(isEmpty(v)) return;

        freq[v]=(freq[v]||0)+1;

    });

    const top=Object.entries(freq)
        .sort((a,b)=>b[1]-a[1])
        .slice(0,10);

    charts.push({

        title:column,

        chart_type:"pie",

        labels:top.map(x=>x[0]),

        values:top.map(x=>x[1])

    });

});

// ======================================================
// SAMPLE DATA
// ======================================================

const sample_data = cleanedRows.slice(0,10);

// ======================================================
// CHART SUMMARY
// ======================================================

const chart_summary = charts.map(c=>({

    title:c.title,

    type:c.chart_type

}));
// ======================================================
// FINAL REPORT OBJECT
// ======================================================

const report = {
    generated_at: new Date().toISOString(),
    engine: "AI Analytics Engine v2.0",
    schema_independent: true,
    total_records: metadata.total_rows,
    total_columns: metadata.total_columns,
    quality_score: quality_analysis.quality_score,
    summary: insights
};

// ======================================================
// AI INPUT PAYLOAD
// ======================================================

const ai_payload = {
    report,
    metadata,
    schema,
    profile,
    kpis,
    statistics,
    relationships,
    quality_analysis,
    category_analysis: categoryAnalysis,
    chart_summary
};

// ======================================================
// RETURN
// ======================================================

return [{
    json: {

        metadata,

        schema,

        profile,

        kpis,

        statistics,

        relationships,

        quality_analysis,

        category_analysis: categoryAnalysis,

        charts,

        chart_summary,

        sample_data,

        report,

        ai_payload,

        data: cleanedRows

    }
}];

