const inputRows = $input.all()
.map(item => item.json);
function normalize(text){
    return String(text)
    .toLowerCase()
    .replace(/[^a-z0-9]/g,"");
}
function detectColumn(columns, keywords){
    return columns.find(col => {
        const normalized = normalize(col);
        return keywords.some(key =>
            normalized.includes(key)
        );
    });
}
const sampleRow = inputRows[0];
const columns = Object.keys(sampleRow);
const detected = {
    student:
    detectColumn(
        columns,
        [
            "student",
            "name",
            "candidate",
            "employee"
        ]
    ),
    attendance:
    detectColumn(
        columns,
        [
            "attendance",
            "attend",
            "present",
            "percentage"
        ]
    ),
    status:
    detectColumn(
        columns,
        [
            "placement",
            "status",
            "result",
            "outcome"
        ]
    ),
    center:
    detectColumn(
        columns,
        [
            "center",
            "location",
            "branch"
        ]
    )

};
let report = {
    rows_received: inputRows.length,
    rows_processed:0,
    rows_removed:0,
    detected_columns: detected,
    issues:{
        invalid_attendance:0,
        duplicates:0,
        empty_rows:0
    }
};
let cleanRows = [];
let duplicateCheck = new Set();
inputRows.forEach(row=>{
    let valid = true;
    if(
        Object.values(row)
        .every(v =>
            v === "" ||
            v === null ||
            v === undefined
        )
    ){
        report.issues.empty_rows++;
        report.rows_removed++;
        return;
    }
    let cleaned = {};
    Object.keys(row).forEach(col=>{
        cleaned[
            normalize(col)
        ] = row[col];
    });
    if(detected.attendance){
        let attendanceValue =
        Number(row[detected.attendance]);
        if(
            isNaN(attendanceValue) ||
            attendanceValue < 0 ||
            attendanceValue > 100
        ){
            report.issues.invalid_attendance++;
            report.rows_removed++;
            valid=false;
        }
    }
    let signature =
    JSON.stringify(row);
    if(duplicateCheck.has(signature)){
        report.issues.duplicates++;
        report.rows_removed++;
        valid=false;
    }
    else{
        duplicateCheck.add(signature);
    }
    if(valid){
        cleanRows.push(row);
    }
});
report.rows_processed =
cleanRows.length;
return cleanRows.map(row=>({
    json:row
}));

